#include <stdio.h>
#include <string.h>

// Define a structure
typedef struct {
    int id;
    char name[30];
    float salary;
} Employee;

void printDetails(Employee e) {
    printf("ID: %d | Name: %s | Salary: $%.2f\n", e.id, e.name, e.salary);
}

void giveRaise(Employee *e) {
    e->salary += 500.0; // Accessing via pointer
}

int main() {
    Employee emp1;

    // 1. Initialization
    emp1.id = 101;
    strcpy(emp1.name, "John Doe");
    emp1.salary = 50000.0;

    printf("--- Initial Details ---\n");
    printDetails(emp1);

    // 2. Modify via Pointer
    giveRaise(&emp1);

    printf("--- After Raise ---\n");
    printDetails(emp1);

    // 3. Array of Structs
    Employee team[2] = {
        {102, "Jane", 60000.0},
        {103, "Bob", 55000.0}
    };

    printf("--- Team Members ---\n");
    for(int i=0; i<2; i++) {
        printDetails(team[i]);
    }

    return 0;
}
